const body = $input.item.json;
const entry = body.entry?.[0];
const change = entry?.changes?.[0];
const message = change?.value?.messages?.[0];
let from, text, to;
if (message) {
  from = message.from;
  text = (message.text?.body || '').toLowerCase().trim();
  to = change.value.metadata?.phone_number_id || '';
} else {
  from = body.from || body.From || '';
  text = (body.text?.body || body.Body || '').toLowerCase().trim();
  to = body.to || body.To || '';
}
return [{ json: { from, text, to, timestamp: Date.now() } }];

const negociosDB = {
  '5532652927': { id: 1, nombre: 'Body Trainer Gym Arboledas', tipo: 'gimnasio', telefono: '5532652927', direccion: 'Calzada de los Jinetes 35, Las Arboledas', horarios: 'Lun-Vie 5AM-11PM | Sáb-Dom 7AM-7PM | 365 días', servicios: [{ nombre: 'Visita del día', precio: 50 }, { nombre: 'Semana', precio: 199 }, { nombre: 'Mensual ilimitado', precio: 699 }, { nombre: 'Estudiante mensual', precio: 599 }] }
};
const { from, text, to } = $input.item.json;
const negocio = negociosDB[to] || negociosDB['5532652927'];
const menuMap = {
  gimnasio: `🏋️ *Bienvenido a ${negocio.nombre}*

¿Qué necesitas?

1️⃣ Ver planes y precios
2️⃣ Horarios y ubicación
3️⃣ Hablar con el equipo
4️⃣ Cómo llegar

_Escribe el número de tu opción_`,
  barberia: `✂️ *Bienvenido a ${negocio.nombre}*

¿Qué necesitas?

1️⃣ Ver servicios y precios
2️⃣ Agendar cita
3️⃣ Horarios
4️⃣ Cómo llegar

_Escribe el número de tu opción_`,
  restaurante: `🍽️ *Bienvenido a ${negocio.nombre}*

¿Qué necesitas?

1️⃣ Ver menú
2️⃣ Reservar mesa
3️⃣ Hacer pedido para llevar
4️⃣ Horarios y ubicación

_Escribe el número de tu opción_`,
  cafe: `☕ *Bienvenido a ${negocio.nombre}*

¿Qué necesitas?

1️⃣ Ver menú
2️⃣ Hacer pedido
3️⃣ Horarios
4️⃣ Cómo llegar

_Escribe el número de tu opción_`
};
const saludos = ['hola','hi','hello','buenas','buenos','buen','inicio','menu','start','0',''];
let msg = '';
if (saludos.some(s => text.startsWith(s))) {
  msg = menuMap[negocio.tipo] || menuMap.gimnasio;
} else if (text === '1') {
  if (negocio.tipo === 'gimnasio') {
    const planes = negocio.servicios.map((s,i) => `${i+1}. *${s.nombre}*: $${s.precio}`).join('
');
    msg = `🏋️ *Planes ${negocio.nombre}*

${planes}

_Para inscribirte escríbenos:_
https://wa.me/${negocio.telefono}`;
  } else {
    const items = negocio.servicios.map(s => `• *${s.nombre}*${s.precio > 0 ? ': $'+s.precio : ''}`).join('
');
    msg = `📋 *Servicios ${negocio.nombre}*

${items}

https://wa.me/${negocio.telefono}`;
  }
} else if (text === '2') {
  msg = `📍 *${negocio.nombre}*

⏰ ${negocio.horarios}

📌 ${negocio.direccion}

🗺️ https://maps.google.com/?q=${encodeURIComponent(negocio.nombre)}`;
} else if (text === '3') {
  msg = `💬 *Hablar con el equipo*

👉 https://wa.me/${negocio.telefono}

Te atendemos de inmediato 😊`;
} else if (text === '4') {
  msg = `🗺️ *Cómo llegar a ${negocio.nombre}*

📌 ${negocio.direccion}

https://maps.google.com/?q=${encodeURIComponent(negocio.nombre + ' ' + negocio.direccion)}`;
} else {
  msg = menuMap[negocio.tipo] || menuMap.gimnasio;
}
return [{ json: { ...$input.item.json, negocio, mensaje_respuesta: msg } }];

const event = $input.item.json;
if (event.type === 'checkout.session.completed') {
  const session = event.data?.object || {};
  return [{ json: { pago_ok: true, stripe_id: session.id, amount: (session.amount_total||0)/100, usuario: session.customer_details?.name, telefono: session.customer_details?.phone } }];
}
return [{ json: { skip: true, event_type: event.type } }];
